prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?enabledTask) AS ?enabledTaskCount)
  (COUNT(DISTINCT ?disabledTask) AS ?disabledTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3c08e52742754da6a4065fc5787131dc" .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .

  # enabled tasks: reachable from at least one start event
  OPTIONAL {
    ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
    FILTER EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
    BIND(?task AS ?enabledTask)
  }

  # disabled tasks: NOT reachable from any start event
  OPTIONAL {
    FILTER NOT EXISTS {
      ?start2 a bboExt:StartEvent ; tai:belongsTo ?choreo .
      ?start2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
    BIND(?task AS ?disabledTask)
  }
}
GROUP BY ?model

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?created
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    (BOUND(?origId) && (?origId = "3c08e52742754da6a4065fc5787131dc")) ||
    (BOUND(?normId) && (?normId = "3c08e52742754da6a4065fc5787131dc"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?enabledTask) AS ?enabledTaskCount)
  (COUNT(DISTINCT ?disabledTask) AS ?disabledTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .

  # all choreographies under this model
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  # enabled tasks: reachable from at least one start event in the same choreography
  OPTIONAL {
    ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
    FILTER EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
    BIND(?task AS ?enabledTask)
  }

  # disabled tasks: NOT reachable from any start event in the same choreography
  OPTIONAL {
    FILTER NOT EXISTS {
      ?start2 a bboExt:StartEvent ; tai:belongsTo ?choreo .
      ?start2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
    BIND(?task AS ?disabledTask)
  }
}
GROUP BY ?model

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?reachableTask) AS ?reachableTaskCount)
WHERE {
  ?model a bboExt:Model ; tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  {
    SELECT (COUNT(DISTINCT ?task0) AS ?taskCount)
    WHERE {
      ?model a bboExt:Model ; tai:originalId "3c08e52742754da6a4065fc5787131dc" .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
      ?task0 a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
    }
  }

  {
    SELECT (COUNT(DISTINCT ?task1) AS ?reachableTaskCount)
    WHERE {
      ?model a bboExt:Model ; tai:originalId "3c08e52742754da6a4065fc5787131dc" .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

      ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
      ?task1 a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .

      FILTER EXISTS {
        ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task1 .
      }
    }
  }
}
GROUP BY ?taskCount ?reachableTaskCount
